def solve(words: Array[String]): Array[Long] = {
    val n = words.length
    if (n == 1) return Array(0L)

    def commonPrefix(s1: String, s2: String): Int = {
        var i = 0
        val len1 = s1.length
        val len2 = s2.length
        while (i < len1 && i < len2 && s1.charAt(i) == s2.charAt(i)) {
            i += 1
        }
        i
    }

    val commonLeft = Array.ofDim[Long](n - 1)
    for (i <- 0 until n - 1) {
        commonLeft(i) = commonPrefix(words(i), words(i + 1)).toLong
    }

    val midCommon = Array.ofDim[Long](n)
    for (k <- 1 until n - 1) {
        midCommon(k) = commonPrefix(words(k - 1), words(k + 1)).toLong
    }

    val prefixMax = Array.ofDim[Long](n - 1)
    if (n - 1 > 0) {
        prefixMax(0) = commonLeft(0)
        for (i <- 1 until n - 1) {
            prefixMax(i) = math.max(prefixMax(i - 1), commonLeft(i))
        }
    }

    val suffixMax = Array.ofDim[Long](n - 1)
    if (n - 1 > 0) {
        suffixMax(n - 2) = commonLeft(n - 2)
        var i = n - 3
        while (i >= 0) {
            suffixMax(i) = math.max(suffixMax(i + 1), commonLeft(i))
            i -= 1
        }
    }

    val ans = Array.ofDim[Long](n)
    for (k <- 0 until n) {
        var cand = 0L
        if (k >= 2) {
            cand = math.max(cand, prefixMax(k - 2))
        }
        if (k >= 1 && k <= n - 2) {
            cand = math.max(cand, midCommon(k))
        }
        if (k <= n - 3) {
            cand = math.max(cand, suffixMax(k + 1))
        }
        ans(k) = cand
    }
    ans
}
```

