def solve(words: Array[String]): Array[Long] = {
    val n = words.length
    if (n <= 1) {
        return Array.fill(n)(0L)
    }

    def commonPrefixLength(a: String, b: String): Int = {
        val len = math.min(a.length, b.length)
        var i = 0
        while (i < len && a(i) == b(i)) {
            i += 1
        }
        i
    }

    val lcp = new Array[Int](n - 1)
    for (i <- 0 until n - 1) {
        lcp(i) = commonPrefixLength(words(i), words(i + 1))
    }

    val leftMax = Array.fill(n - 1)(0)
    if (n - 1 > 0) {
        leftMax(0) = lcp(0)
        for (i <- 1 until n - 1) {
            leftMax(i) = math.max(leftMax(i - 1), lcp(i))
        }
    }

    val rightMax = Array.fill(n - 1)(0)
    if (n - 1 > 0) {
        rightMax(n - 2) = lcp(n - 2)
        for (i <- (n - 3) to 0 by -1) {
            rightMax(i) = math.max(rightMax(i + 1), lcp(i))
        }
    }

    val answer = Array.ofDim[Long](n)
    for (i <- 0 until n) {
        var candidate: Long = 0L
        if (i - 2 >= 0) {
            candidate = candidate max leftMax(i - 2)
        }
        if (i + 1 <= n - 2) {
            candidate = candidate max rightMax(i + 1)
        }
        if (i >= 1 && i <= n - 2) {
            val mid = commonPrefixLength(words(i - 1), words(i + 1))
            candidate = candidate max mid
        }
        answer(i) = candidate
    }
    answer
}
```

### Explanation
1. **Initial Setup**: The solution first checks if the input array has only one element (or none) and returns an array of zeros since no adjacent pairs exist after removal.
2. **Common Prefix Calculation**: The helper function `commonPrefixLength` computes the LCP length between two strings by comparing characters from the start until a mismatch is found.
3. **LCP Array Construction**: The `lcp` array stores the LCP lengths for each adjacent pair in the original array.
4. **Prefix and Suffix Arrays**: The `leftMax` and `rightMax` arrays are built to store the maximum LCP values from the start up to each index and from each index to the end, respectively.
5. **Processing Removals**: For each index `i`:
   - The left segment's maximum LCP (if any) is retrieved from `leftMax`.
   - The right segment's maximum LCP (if any) is retrieved from `rightMax`.
   - The boundary pair's LCP (between `words[i-1]` and `words[i+1]`) is computed if applicable.
   - The maximum of these values is stored in the result array.
6. **Efficiency**: By leveraging precomputed arrays, the solution efficiently handles each removal in constant time, making it optimal for large inputs as specified.
